     * @throws SAXException if the XML format is invalid or cannot be parsed
     */
    public Document loadConfig(String configPath) 
            throws IllegalArgumentException, IOException, ParserConfigurationException, SAXException {

        // 1. Validate input
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Configuration path cannot be null or empty.");
        }

        File configFile = new File(configPath);
        if (!configFile.exists()) {
            throw new IOException("Configuration file not found at path: " + configPath);
        }

        // 2. Create DocumentBuilderFactory
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // 3. Configure Security Features to prevent XXE (XML External Entity) attacks
        try {
